let name;
console.log(name);  // undefined
// "我声明了这个变量，但还没给它值"

function greet() {
  console.log("hi");
  // 没有 return
}
console.log(greet());  // undefined
// 函数执行完没返回值，默认返回 undefined

const user = { name: "Alice" };
console.log(user.age);  // undefined
// 对象上没有 age 属性 → undefined

function add(a, b) {
  console.log(b);  // undefined
}
add(1);  // 只传了 a，b 没传 → undefined

const arr = [1, 2, 3];
console.log(arr[99]);  // undefined
// 索引超出范围 → undefined

function findUser(id) {
  // 数据库里找不到用户
  return null;  // "我查过了，确实没有"，而不是 undefined
}

const user = findUser(999);
if (user === null) {
  console.log("用户不存在");
}

let selectedUser = { name: "Alice" };

// 用户取消选择 → 清空引用
selectedUser = null;  // 主动清空，释放内存

if (selectedUser === null) {
  console.log("没有选中任何用户");
}

let currentUser = null;  // 现在还没登录，但将来会有

// 用户登录后
currentUser = { name: "Alice" };

// 退出登录
currentUser = null;  // 重新清空

typeof undefined  // "undefined" ✅ 正确
typeof null        // "object"    ❌ BUG！

// ⚠️ null 是原始类型，不是对象！
// typeof 的结果不可靠地判断 null

// 方法 1：严格相等（推荐）
if (x === null) { ... }

// 方法 2：typeof + 严格相等（冗余但安全）
if (typeof x === 'object' && x === null) { ... }
// 注意：typeof null 返回 "object"，所以需要双重检查

// 方法 1：严格相等（推荐）
if (x === undefined) { ... }

// 方法 2：typeof（更安全，变量未声明也不报错）
if (typeof x === 'undefined') { ... }
// typeof 对未声明的变量也不报错，更安全

// 方法 1：== null 技巧（唯一推荐用 == 的场景）
if (x == null) { ... }
// 等价于 x === null || x === undefined

// 方法 2：显式写法（更清晰）
if (x === null || x === undefined) { ... }

