// ✅ 判断 null
if (x === null) { ... }

// ✅ 判断 undefined
if (x === undefined) { ... }
if (typeof x === 'undefined') { ... }  // 变量可能未声明时

// ✅ 同时判断 null 和 undefined
if (x == null) { ... }  // 唯一推荐用 == 的场景

// ❌ 禁止
if (x == undefined) { ... }  // 用 === 代替
if (typeof x === 'object') { ... }  // null 也返回 "object"！
